2. Create `validateGroupMembership.ts`:
```typescript
// ./server/middleware/validateGroupMembership.ts
import { Request, Response, NextFunction } from 'express';
import { prisma } from '../prisma';

export async function validateGroupMembership(
  req: Request,
  res: Response,
  next: NextFunction
) {
  const { groupId } = req.params;
  const group = await prisma.group.findUnique({ where: { id: groupId } });

  if (!group) {
    return res.status(404).json({ error: 'Group not found' });
  }

  // Attach group to request for downstream handlers
  (req as any).group = group;
  next();
}
```

**Why This First**: This change immediately reduces route handler size while establishing a pattern for middleware-based validation that can be reused across routes.
